request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (SAMPLE(?modelName) AS ?modelName)
WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }

  FILTER(
    STR(?model) = STR(URI(CONCAT("", "")))
  )

  {
    ?model tai:normalizedId "1f1b01e0a85340689b6df314b32bb4b6" .
  }
  UNION
  {
    ?model tai:originalId "1f1b01e0a85340689b6df314b32bb4b6" .
  }
  UNION
  {
    ?model tai:normalizedId ?nid .
    FILTER(STR(?nid) = "1f1b01e0a85340689b6df314b32bb4b6")
  }
  UNION
  {
    ?model tai:originalId ?oid .
    FILTER(STR(?oid) = "1f1b01e0a85340689b6df314b32bb4b6")
  }

  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?definitions .
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo ?choreo .
}
GROUP BY ?taskCount
LIMIT 1
